  1→import React, { useState } from 'react';
  2→import { User } from '../types';
  3→import { simulateCitation, CitationSimulationResult, AIEngineResponse } from '../services/ai-citation-simulator';
  4→import {
  5→  ArrowLeft, Search, Loader2, Sparkles, Zap, Eye, MessageSquare,
  6→  ThumbsUp, ThumbsDown, Minus, CheckCircle, XCircle, AlertTriangle,
  7→  Lightbulb, Users, BarChart3, Globe,
  8→} from 'lucide-react';
  9→import PageHeader from '../components/layout/PageHeader';
 10→
 11→interface Props {
 12→  onBack: () => void;
 13→  user: User | null;
 14→  onDeductCredits: (amount: number) => boolean;
 15→}
 16→
 17→const CREDIT_COST = 6;
 18→
 19→const ENGINE_STYLES: Record<string, { color: string; bg: string; gradient: string }> = {
 20→  ChatGPT: { color: 'text-emerald-400', bg: 'bg-emerald-500/10', gradient: 'from-emerald-500/20 to-emerald-600/5' },
 21→  Claude: { color: 'text-orange-400', bg: 'bg-orange-500/10', gradient: 'from-orange-500/20 to-orange-600/5' },
 22→  Perplexity: { color: 'text-blue-400', bg: 'bg-blue-500/10', gradient: 'from-blue-500/20 to-blue-600/5' },
 23→  Gemini: { color: 'text-purple-400', bg: 'bg-purple-500/10', gradient: 'from-purple-500/20 to-purple-600/5' },
 24→  'AI Overviews': { color: 'text-rose-400', bg: 'bg-rose-500/10', gradient: 'from-rose-500/20 to-rose-600/5' },
 25→};
 26→
 27→const MentionBadge: React.FC<{ type: AIEngineResponse['mentionType'] }> = ({ type }) => {
 28→  const styles = {
 29→    direct: { label: 'Mention directe', color: 'text-emerald-400', bg: 'bg-emerald-500/10', icon: CheckCircle },
 30→    indirect: { label: 'Mention indirecte', color: 'text-amber-400', bg: 'bg-amber-500/10', icon: AlertTriangle },
 31→    comparison: { label: 'En comparaison', color: 'text-blue-400', bg: 'bg-blue-500/10', icon: Users },
 32→    absent: { label: 'Non mentionné', color: 'text-red-400', bg: 'bg-red-500/10', icon: XCircle },
 33→  };
 34→  const s = styles[type];
 35→  const Icon = s.icon;
 36→  return (
 37→    <span className={`inline-flex items-center gap-1 text-[10px] font-semibold px-2 py-0.5 rounded-full ${s.bg} ${s.color}`}>
 38→      <Icon size={10} /> {s.label}
 39→    </span>
 40→  );
 41→};
 42→
 43→const SentimentIcon: React.FC<{ sentiment: AIEngineResponse['sentiment'] }> = ({ sentiment }) => {
 44→  if (sentiment === 'positive') return <ThumbsUp size={12} className="text-emerald-400" />;
 45→  if (sentiment === 'negative') return <ThumbsDown size={12} className="text-red-400" />;
 46→  return <Minus size={12} className="text-gray-500" />;
 47→};
 48→
 49→const EngineCard: React.FC<{ engine: AIEngineResponse; brandName: string }> = ({ engine, brandName }) => {
 50→  const style = ENGINE_STYLES[engine.engine] || ENGINE_STYLES.ChatGPT;
 51→  const [expanded, setExpanded] = useState(true);
 52→
 53→  // Highlight brand mentions in the response
 54→  const highlightBrand = (text: string) => {
 55→    if (!brandName) return text;
 56→    const regex = new RegExp(`(${brandName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})`, 'gi');
 57→    const parts = text.split(regex);
 58→    return parts.map((part, i) =>
 59→      regex.test(part) ? <mark key={i} className="bg-purple-500/30 text-purple-200 rounded px-0.5">{part}</mark> : part
 60→    );
 61→  };
 62→
 63→  return (
 64→    <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl overflow-hidden">
 65→      <div className={`bg-gradient-to-r ${style.gradient} px-4 py-3 flex items-center gap-3 border-b border-[var(--border-subtle)]`}>
 66→        <div className={`w-8 h-8 rounded-lg ${style.bg} flex items-center justify-center`}>
 67→          <MessageSquare size={14} className={style.color} />
 68→        </div>
 69→        <div className="flex-1">
 70→          <div className="flex items-center gap-2">
 71→            <span className={`text-sm font-bold ${style.color}`}>{engine.engine}</span>
 72→            <MentionBadge type={engine.mentionType} />
 73→          </div>
 74→        </div>
 75→        <div className="flex items-center gap-3">
 76→          <div className="flex items-center gap-1">
 77→            <SentimentIcon sentiment={engine.sentiment} />
 78→            <span className="text-xs text-gray-500">{engine.sentiment}</span>
 79→          </div>
 80→          <div className="text-right">
 81→            <span className={`text-lg font-bold ${engine.mentionScore >= 60 ? 'text-emerald-400' : engine.mentionScore >= 30 ? 'text-amber-400' : 'text-red-400'}`}>
 82→              {engine.mentionScore}
 83→            </span>
 84→            <span className="text-[10px] text-gray-500">/100</span>
 85→          </div>
 86→        </div>
 87→      </div>
 88→      <div className="p-4">
 89→        <div className="bg-white/[0.03]/50 rounded-xl p-4 border border-[var(--border-subtle)]">
 90→          <p className="text-sm text-gray-300 leading-relaxed italic">"{highlightBrand(engine.response)}"</p>
 91→        </div>
 92→        {engine.excerpt && engine.mentionType !== 'absent' && (
 93→          <div className="mt-3 flex items-start gap-2">
 94→            <Eye size={12} className="text-purple-400 mt-0.5 shrink-0" />
 95→            <p className="text-xs text-gray-500">Extrait : <span className="text-purple-300">"{engine.excerpt}"</span></p>
 96→          </div>
 97→        )}
 98→      </div>
 99→    </div>
100→  );
101→};
102→
103→const AiCitationSimulator: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
104→  const [query, setQuery] = useState('');
105→  const [brandName, setBrandName] = useState('');
106→  const [brandUrl, setBrandUrl] = useState('');
107→  const [industry, setIndustry] = useState('');
108→  const [isSimulating, setIsSimulating] = useState(false);
109→  const [result, setResult] = useState<CitationSimulationResult | null>(null);
110→
111→  const handleSimulate = async () => {
112→    if (!query || !brandName || !brandUrl) return;
113→    const canProceed = onDeductCredits(CREDIT_COST);
114→    if (!canProceed) return;
115→
116→    setIsSimulating(true);
117→    setResult(null);
118→    try {
119→      const output = await simulateCitation(query, brandName, brandUrl, industry || undefined);
120→      setResult(output);
121→    } catch (err) {
122→      console.error('Simulation failed:', err);
123→    } finally {
124→      setIsSimulating(false);
125→    }
126→  };
127→
128→  const directMentions = result?.engines.filter(e => e.mentionType === 'direct').length || 0;
129→  const avgScore = result ? Math.round(result.engines.reduce((sum, e) => sum + e.mentionScore, 0) / result.engines.length) : 0;
130→
131→  return (
132→    <div className="page-enter">
133→      <PageHeader title="AI Citation Simulator" description="Simulez la visibilité de votre marque dans les réponses IA" />
134→      {/* Header */}
135→      <div className="flex items-center gap-4 mb-8">
136→        <div className="flex-1">
137→          <div className="flex items-center gap-3">
138→            <h1 className="text-2xl font-bold text-white">Simulateur de <span className="gradient-text">Citation IA</span></h1>
139→            <span className="bg-blue-500/10 text-blue-400 text-xs font-bold px-2.5 py-1 rounded-full border border-blue-500/20 flex items-center gap-1">
140→              <Sparkles size={10} /> NOUVEAU
141→            </span>
142→          </div>
143→          <p className="text-sm text-gray-500 mt-1">Simulez comment ChatGPT, Claude, Perplexity, Gemini et AI Overviews parlent de votre marque</p>
144→        </div>
145→      </div>
146→
147→      {/* Input Form */}
148→      <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6 mb-8">
149→        <div className="space-y-4">
150→          <div>
151→            <label className="block text-sm font-medium text-gray-300 mb-1.5">Question à simuler <span className="text-red-400">*</span></label>
152→            <div className="relative">
153→              <Search size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" />
154→              <input value={query} onChange={e => setQuery(e.target.value)}
155→                placeholder="Quel est le meilleur outil pour optimiser sa visibilité IA ?"
156→                className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl pl-11 pr-4 py-3 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors"
157→                onKeyDown={e => e.key === 'Enter' && handleSimulate()} />
158→            </div>
159→          </div>
160→          <div className="grid md:grid-cols-3 gap-4">
161→            <div>
162→              <label className="block text-sm font-medium text-gray-300 mb-1.5">Votre marque <span className="text-red-400">*</span></label>
163→              <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="CitedBy.ai"
164→                className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
165→            </div>
166→            <div>
167→              <label className="block text-sm font-medium text-gray-300 mb-1.5">URL de la marque <span className="text-red-400">*</span></label>
168→              <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://citedby.ai"
169→                className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
170→            </div>
171→            <div>
172→              <label className="block text-sm font-medium text-gray-300 mb-1.5">Secteur d'activité</label>
173→              <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="SaaS, Marketing digital..."
174→                className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
175→            </div>
176→          </div>
177→          <button onClick={handleSimulate} disabled={isSimulating || !query || !brandName || !brandUrl}
178→            className={`w-full md:w-auto px-8 py-3 rounded-xl font-semibold text-sm flex items-center justify-center gap-2 transition-all ${
179→              isSimulating || !query || !brandName || !brandUrl ? 'bg-gray-700/50 text-gray-500 cursor-not-allowed' : 'btn-gradient text-white'
180→            }`}>
181→            {isSimulating ? (<><Loader2 size={16} className="animate-spin" /> Simulation en cours...</>) : (<><Zap size={16} /> Simuler ({CREDIT_COST} Gas)</>)}
182→          </button>
183→        </div>
184→      </div>
185→
186→      {/* Loading State */}
187→      {isSimulating && (
188→        <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-12 flex flex-col items-center justify-center text-center mb-8">
189→          <div className="flex items-center gap-4 mb-6">
190→            {['ChatGPT', 'Claude', 'Perplexity', 'Gemini', 'AI Overviews'].map((name, i) => {
191→              const style = ENGINE_STYLES[name];
192→              return (
193→                <div key={name} className={`w-12 h-12 rounded-xl ${style.bg} flex items-center justify-center`}
194→                  style={{ animation: `pulse 1.5s ease-in-out ${i * 0.3}s infinite` }}>
195→                  <MessageSquare size={20} className={style.color} />
196→                </div>
197→              );
198→            })}
199→          </div>
200→          <h3 className="text-lg font-bold text-gray-300 mb-2">Interrogation des IA en cours...</h3>
201→          <p className="text-sm text-gray-500">Simulation des réponses de 5 moteurs de réponse IA</p>
202→        </div>
203→      )}
204→
205→      {/* Results */}
206→      {result && !isSimulating && (
207→        <div className="space-y-6 page-enter">
208→          {/* Score Overview */}
209→          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
210→            <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-4 text-center">
211→              <p className={`text-3xl font-bold ${result.overallScore >= 60 ? 'text-emerald-400' : result.overallScore >= 30 ? 'text-amber-400' : 'text-red-400'}`}>
212→                {result.overallScore}
213→              </p>
214→              <p className="text-xs text-gray-500 mt-1">Score global</p>
215→            </div>
216→            <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-4 text-center">
217→              <p className="text-3xl font-bold text-purple-400">{directMentions}</p>
218→              <p className="text-xs text-gray-500 mt-1">Mentions directes</p>
219→            </div>
220→            <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-4 text-center">
221→              <p className="text-3xl font-bold text-blue-400">{result.engines.filter(e => e.citationPresent).length}</p>
222→              <p className="text-xs text-gray-500 mt-1">Citations avec lien</p>
223→            </div>
224→            <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-4 text-center">
225→              <p className="text-3xl font-bold text-amber-400">{result.competitorsMentioned.length}</p>
226→              <p className="text-xs text-gray-500 mt-1">Concurrents cités</p>
227→            </div>
228→          </div>
229→
230→          {/* Query reminder */}
231→          <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-4 flex items-center gap-3 border-l-2 border-purple-500/50">
232→            <Search size={16} className="text-purple-400 shrink-0" />
233→            <div>
234→              <p className="text-xs text-gray-500">Question simulée :</p>
235→              <p className="text-sm text-gray-300 font-medium">"{result.query}"</p>
236→            </div>
237→          </div>
238→
239→          {/* Engine Responses */}
240→          <div>
241→            <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-4">Réponses simulées par moteur</h3>
242→            <div className="grid md:grid-cols-2 gap-4">
243→              {result.engines.map((engine, i) => (
244→                <EngineCard key={i} engine={engine} brandName={result.brandName} />
245→              ))}
246→            </div>
247→          </div>
248→
249→          {/* Competitors & Improvements */}
250→          <div className="grid md:grid-cols-2 gap-6">
251→            {result.competitorsMentioned.length > 0 && (
252→              <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
253→                <h3 className="text-sm font-semibold text-gray-300 mb-3 flex items-center gap-2">
254→                  <Users size={14} className="text-red-400" /> Concurrents mentionnés
255→                </h3>
256→                <div className="flex flex-wrap gap-2">
257→                  {result.competitorsMentioned.map((comp, i) => (
258→                    <span key={i} className="px-3 py-1.5 bg-red-500/5 border border-red-500/10 rounded-lg text-xs text-red-300 font-medium">
259→                      {comp}
260→                    </span>
261→                  ))}
262→                </div>
263→              </div>
264→            )}
265→            <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
266→              <h3 className="text-sm font-semibold text-gray-300 mb-3 flex items-center gap-2">
267→                <Lightbulb size={14} className="text-amber-400" /> Comment améliorer votre visibilité
268→              </h3>
269→              <ul className="space-y-2">
270→                {result.improvements.map((imp, i) => (
271→                  <li key={i} className="flex items-start gap-2 text-sm text-gray-400">
272→                    <span className="text-purple-400 mt-0.5 shrink-0">→</span>
273→                    {imp}
274→                  </li>
275→                ))}
276→              </ul>
277→            </div>
278→          </div>
279→        </div>
280→      )}
281→
282→      {/* Empty State */}
283→      {!result && !isSimulating && (
284→        <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-12 flex flex-col items-center justify-center text-center">
285→          <div className="flex items-center gap-3 mb-6">
286→            {Object.entries(ENGINE_STYLES).map(([name, style]) => (
287→              <div key={name} className={`w-14 h-14 rounded-xl ${style.bg} flex flex-col items-center justify-center gap-1`}>
288→                <MessageSquare size={18} className={style.color} />
289→                <span className={`text-[8px] font-bold ${style.color}`}>{name.slice(0, 3)}</span>
290→              </div>
291→            ))}
292→          </div>
293→          <h3 className="text-lg font-bold text-gray-300 mb-2">Simulateur de Citation</h3>
294→          <p className="text-sm text-gray-500 max-w-md">Posez une question et découvrez si ChatGPT, Claude, Perplexity, Gemini et AI Overviews mentionneraient votre marque dans leur réponse</p>
295→        </div>
296→      )}
297→    </div>
298→  );
299→};
300→
301→export default AiCitationSimulator;
