  1→// pages/MultilingualCitations.tsx
  2→// Analyse de citations multilingues — matrice langue x moteur IA
  3→
  4→import React, { useState } from 'react';
  5→import { Globe, Play, ChevronDown, ChevronUp, CheckCircle, XCircle, Loader2 } from 'lucide-react';
  6→import { SUPPORTED_LANGUAGES, type LanguageCode } from '../services/v3/language-query-templates';
  7→import { runMultilingualCheck, type MultilingualConfig, type MultilingualReport, type LanguageCitationResult } from '../services/v3/multilingual-checker';
  8→import LanguageCitationMatrix from '../components/LanguageCitationMatrix';
  9→import LanguageOpportunityCard from '../components/LanguageOpportunityCard';
 10→
 11→interface Props {
 12→  onBack?: () => void;
 13→  user: { name: string; email: string } | null;
 14→  onDeductCredits?: (amount: number) => void;
 15→}
 16→
 17→export default function MultilingualCitations({ onBack, user, onDeductCredits }: Props) {
 18→  // === CONFIG STATE ===
 19→  const [url, setUrl] = useState('');
 20→  const [brand, setBrand] = useState('');
 21→  const [industry, setIndustry] = useState('');
 22→  const [useCase, setUseCase] = useState('');
 23→  const [selectedLanguages, setSelectedLanguages] = useState<LanguageCode[]>(['fr', 'en']);
 24→
 25→  // === ANALYSIS STATE ===
 26→  const [isRunning, setIsRunning] = useState(false);
 27→  const [progress, setProgress] = useState({ current: 0, total: 0, language: '', engine: '', status: '' });
 28→  const [report, setReport] = useState<MultilingualReport | null>(null);
 29→  const [expandedLanguage, setExpandedLanguage] = useState<string | null>(null);
 30→
 31→  const creditCost = selectedLanguages.length * 3;
 32→
 33→  function toggleLanguage(code: LanguageCode) {
 34→    setSelectedLanguages(prev =>
 35→      prev.includes(code) ? prev.filter(l => l !== code) : [...prev, code]
 36→    );
 37→  }
 38→
 39→  async function handleAnalyze() {
 40→    if (!url || !brand || !industry || selectedLanguages.length === 0) return;
 41→
 42→    setIsRunning(true);
 43→    setReport(null);
 44→    try {
 45→      const config: MultilingualConfig = {
 46→        url, brand, industry, useCase: useCase || undefined,
 47→        languages: selectedLanguages,
 48→      };
 49→      const result = await runMultilingualCheck(config, setProgress);
 50→      setReport(result);
 51→      onDeductCredits?.(creditCost);
 52→    } catch (error) {
 53→      console.error('Multilingual check failed:', error);
 54→    } finally {
 55→      setIsRunning(false);
 56→    }
 57→  }
 58→
 59→  // Grouper les resultats par langue pour le detail accordion
 60→  function getResultsByLanguage(lang: string): LanguageCitationResult[] {
 61→    return report?.results.filter(r => r.language === lang) || [];
 62→  }
 63→
 64→  return (
 65→    <div className="space-y-6 page-enter">
 66→
 67→      {/* === HEADER === */}
 68→      <div className="flex items-center justify-between">
 69→        <div>
 70→          <h1 className="text-2xl font-bold text-white flex items-center gap-2">
 71→            <Globe className="w-6 h-6 text-blue-400" />
 72→            Citations par langue
 73→          </h1>
 74→          <p className="text-[14px] text-zinc-400 mt-1">
 75→            Analysez votre visibilite dans les moteurs IA par langue
 76→          </p>
 77→        </div>
 78→        {report && (
 79→          <div className="text-right">
 80→            <div className="text-[13px] text-zinc-500">Analyse du</div>
 81→            <div className="text-[14px] text-zinc-300 font-medium">
 82→              {new Date(report.timestamp).toLocaleDateString('fr-FR')}
 83→            </div>
 84→          </div>
 85→        )}
 86→      </div>
 87→
 88→      {/* === CONFIGURATION === */}
 89→      <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
 90→        <h2 className="text-white font-semibold mb-4">Configuration</h2>
 91→
 92→        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
 93→          <div>
 94→            <label className="block text-[13px] text-zinc-400 mb-1.5">URL du site</label>
 95→            <input
 96→              type="url"
 97→              value={url}
 98→              onChange={e => setUrl(e.target.value)}
 99→              placeholder="https://example.com"
100→              className="w-full px-3 py-2 rounded-lg bg-white/[0.04] border border-white/[0.06] text-white text-[14px] placeholder:text-zinc-600 focus:border-blue-500/50 focus:outline-none transition-colors"
101→            />
102→          </div>
103→          <div>
104→            <label className="block text-[13px] text-zinc-400 mb-1.5">Nom de la marque</label>
105→            <input
106→              type="text"
107→              value={brand}
108→              onChange={e => setBrand(e.target.value)}
109→              placeholder="Ma Marque"
110→              className="w-full px-3 py-2 rounded-lg bg-white/[0.04] border border-white/[0.06] text-white text-[14px] placeholder:text-zinc-600 focus:border-blue-500/50 focus:outline-none transition-colors"
111→            />
112→          </div>
113→          <div>
114→            <label className="block text-[13px] text-zinc-400 mb-1.5">Secteur / Industrie</label>
115→            <input
116→              type="text"
117→              value={industry}
118→              onChange={e => setIndustry(e.target.value)}
119→              placeholder="SaaS, Marketing digital, E-commerce..."
120→              className="w-full px-3 py-2 rounded-lg bg-white/[0.04] border border-white/[0.06] text-white text-[14px] placeholder:text-zinc-600 focus:border-blue-500/50 focus:outline-none transition-colors"
121→            />
122→          </div>
123→          <div>
124→            <label className="block text-[13px] text-zinc-400 mb-1.5">Cas d'usage <span className="text-zinc-600">(optionnel)</span></label>
125→            <input
126→              type="text"
127→              value={useCase}
128→              onChange={e => setUseCase(e.target.value)}
129→              placeholder="SEO, gestion de projet..."
130→              className="w-full px-3 py-2 rounded-lg bg-white/[0.04] border border-white/[0.06] text-white text-[14px] placeholder:text-zinc-600 focus:border-blue-500/50 focus:outline-none transition-colors"
