 71→// ── Code Preview with Copy ──
 72→const CodePreview: React.FC<{ code: string; language: string; title: string }> = ({ code, language, title }) => {
 73→  const [copied, setCopied] = useState(false);
 74→
 75→  const handleCopy = () => {
 76→    navigator.clipboard.writeText(code);
 77→    setCopied(true);
 78→    setTimeout(() => setCopied(false), 2000);
 79→  };
 80→
 81→  const handleDownload = () => {
 82→    const ext = language === 'xml' ? 'xml' : language === 'json' ? 'json' : 'html';
 83→    const mime = language === 'xml' ? 'application/xml' : language === 'json' ? 'application/json' : 'text/html';
 84→    const blob = new Blob([code], { type: mime });
 85→    const url = URL.createObjectURL(blob);
 86→    const a = document.createElement('a');
 87→    a.href = url;
 88→    a.download = title.toLowerCase().replace(/\s+/g, '-') + '.' + ext;
 89→    a.click();
 90→    URL.revokeObjectURL(url);
 91→  };
 92→
 93→  return (
 94→    <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl overflow-hidden">
 95→      <div className="flex items-center justify-between px-4 py-3 border-b border-[var(--border-subtle)]">
 96→        <div className="flex items-center gap-2">
 97→          <Code size={14} className="text-purple-400" />
 98→          <span className="text-sm font-semibold text-gray-300">{title}</span>
 99→          <span className="text-xs text-gray-500 bg-white/[0.03] px-2 py-0.5 rounded">{language.toUpperCase()}</span>
100→        </div>
101→        <div className="flex items-center gap-2">
102→          <button onClick={handleCopy} className="flex items-center gap-1.5 text-xs text-gray-400 hover:text-purple-400 transition-colors px-2 py-1 rounded hover:bg-white/[0.03]">
103→            {copied ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
104→            {copied ? 'Copié !' : 'Copier'}
105→          </button>
106→          <button onClick={handleDownload} className="flex items-center gap-1.5 text-xs text-gray-400 hover:text-purple-400 transition-colors px-2 py-1 rounded hover:bg-white/[0.03]">
107→            <Download size={12} /> Télécharger
108→          </button>
109→        </div>
110→      </div>
111→      <pre className="p-4 text-xs text-gray-300 overflow-x-auto max-h-[500px] overflow-y-auto leading-relaxed">
112→        <code>{code}</code>
113→      </pre>
114→    </div>
115→  );
