225→const generateTimeline = (): CrawlEvent[] => {
226→  const pages = ['/index.html', '/about', '/products', '/blog/ai-guide', '/faq', '/pricing', '/contact', '/blog/seo-tips', '/docs/api', '/team'];
227→  const bots = [
228→    { id: 'gptbot', name: 'GPTBot', icon: 'G' },
229→    { id: 'claudebot', name: 'ClaudeBot', icon: 'A' },
230→    { id: 'google-extended', name: 'Google-Extended', icon: 'G' },
231→    { id: 'perplexitybot', name: 'PerplexityBot', icon: 'P' },
232→    { id: 'chatgpt-user', name: 'ChatGPT-User', icon: 'C' },
233→    { id: 'anthropic-ai', name: 'anthropic-ai', icon: 'A' },
234→  ];
235→
236→  const events: CrawlEvent[] = [];
237→  const now = Date.now();
238→
239→  for (let i = 0; i < 20; i++) {
240→    const bot = bots[Math.floor(Math.random() * bots.length)];
241→    const minutesAgo = Math.floor(Math.random() * 120);
242→    const timestamp = new Date(now - minutesAgo * 60000);
243→    const statuses: ('success' | 'blocked' | 'error')[] = ['success', 'success', 'success', 'success', 'success', 'blocked', 'error'];
244→
245→    events.push({
246→      botId: bot.id,
247→      botName: bot.name,
248→      botIcon: bot.icon,
249→      timestamp: timestamp.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' }),
250→      page: pages[Math.floor(Math.random() * pages.length)],
251→      status: statuses[Math.floor(Math.random() * statuses.length)],
252→      responseTime: Math.floor(Math.random() * 800) + 50,
253→    });
254→  }
255→
256→  return events.sort((a, b) => b.timestamp.localeCompare(a.timestamp));
257→};
