293→const MissionOrders: React.FC<MissionOrdersProps> = ({ onBack, user, onNavigate }) => {
294→  const [missions, setMissions] = useState<MissionOrder[]>(DEMO_MISSIONS);
295→  const [searchQuery, setSearchQuery] = useState('');
296→  const [statusFilter, setStatusFilter] = useState<MissionStatus | 'all'>('all');
297→  const [expandedMission, setExpandedMission] = useState<string | null>(null);
298→  const [sortBy, setSortBy] = useState<'date' | 'budget' | 'score'>('date');
299→  const [proofModal, setProofModal] = useState<{ missionId: string; recId: string } | null>(null);
300→  const [proofForm, setProofForm] = useState({ type: 'lien' as ProofType, description: '', url: '' });
301→
302→  useEffect(() => {
303→    if (proofModal) { document.body.style.overflow = 'hidden'; }
304→    return () => { document.body.style.overflow = ''; };
305→  }, [proofModal]);
306→
307→  const kpis = useMemo(() => ({
308→    total: missions.length,
309→    nouveau: missions.filter(m => m.status === 'nouveau').length,
310→    en_cours: missions.filter(m => ['accepte', 'en_cours', 'livraison'].includes(m.status)).length,
311→    termine: missions.filter(m => m.status === 'termine').length,
312→    refuse: missions.filter(m => m.status === 'refuse').length,
313→    totalBudget: missions.filter(m => m.status !== 'refuse').reduce((sum, m) => sum + m.budget, 0),
314→    avgScore: Math.round(missions.reduce((sum, m) => sum + m.aeoScore, 0) / missions.length),
315→    escrowBloque: missions.filter(m => m.escrowStatus === 'bloque' || m.escrowStatus === 'en_validation').reduce((s, m) => s + m.budget, 0),
316→  }), [missions]);
317→
318→  const filteredMissions = useMemo(() => {
319→    let filtered = missions;
320→    if (statusFilter !== 'all') filtered = filtered.filter(m => m.status === statusFilter);
321→    if (searchQuery.trim()) {
322→      const q = searchQuery.toLowerCase();
323→      filtered = filtered.filter(m =>
324→        m.clientName.toLowerCase().includes(q) || m.clientCompany.toLowerCase().includes(q) ||
325→        m.analyzedUrl.toLowerCase().includes(q) || m.id.toLowerCase().includes(q)
326→      );
327→    }
328→    return [...filtered].sort((a, b) => {
329→      if (sortBy === 'budget') return b.budget - a.budget;
330→      if (sortBy === 'score') return a.aeoScore - b.aeoScore;
331→      return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
332→    });
333→  }, [missions, statusFilter, searchQuery, sortBy]);
334→
335→  const handleStatusChange = (missionId: string, newStatus: MissionStatus) => {
336→    setMissions(prev => prev.map(m => {
337→      if (m.id !== missionId) return m;
338→      const updates: Partial<MissionOrder> = { status: newStatus, updatedAt: new Date().toISOString() };
339→      if (newStatus === 'accepte') updates.escrowStatus = 'bloque';
340→      if (newStatus === 'livraison') updates.escrowStatus = 'en_validation';
341→      if (newStatus === 'termine') updates.escrowStatus = 'libere';
342→      return { ...m, ...updates };
343→    }));
344→  };
345→
346→  const handleToggleRecommendation = (missionId: string, recId: string) => {
347→    setMissions(prev => prev.map(m => {
348→      if (m.id !== missionId) return m;
349→      const completed = m.completedRecommendations || [];
350→      const isCompleted = completed.includes(recId);
351→      return {
352→        ...m,
353→        completedRecommendations: isCompleted ? completed.filter(id => id !== recId) : [...completed, recId],
354→        updatedAt: new Date().toISOString(),
355→      };
356→    }));
357→  };
358→
359→  const handleSubmitProof = () => {
360→    if (!proofModal || !proofForm.description.trim()) return;
361→    setMissions(prev => prev.map(m => {
362→      if (m.id !== proofModal.missionId) return m;
363→      return {
364→        ...m,
365→        recommendations: m.recommendations.map(r => {
366→          if (r.id !== proofModal.recId) return r;
367→          return {
368→            ...r,
369→            proof: {
370→              type: proofForm.type,
371→              label: proofForm.type === 'lien' ? 'Lien livrable' : proofForm.type === 'code' ? 'Code livré' : proofForm.type === 'capture' ? 'Capture d\'écran' : 'Rapport d\'audit',
372→              url: proofForm.url,
373→              description: proofForm.description,
374→              submittedAt: new Date().toISOString(),
375→            },
376→            platformValidation: 'en_attente' as PlatformValidation,
377→          };
378→        }),
379→        updatedAt: new Date().toISOString(),
380→      };
381→    }));
382→    setProofModal(null);
383→    setProofForm({ type: 'lien', description: '', url: '' });
384→  };
385→
386→  const handleReaudit = (missionId: string) => {
387→    setMissions(prev => prev.map(m => m.id === missionId ? { ...m, isReauditing: true } : m));
388→    // Simulated re-audit with random improvement
389→    setTimeout(() => {
390→      setMissions(prev => prev.map(m => {
391→        if (m.id !== missionId) return m;
392→        const improvement = Math.floor(Math.random() * 30) + 15;
393→        const newScore = Math.min(100, m.aeoScore + improvement);
394→        return { ...m, postAuditScore: newScore, postAuditDate: new Date().toISOString(), isReauditing: false };
395→      }));
396→    }, 3000);
397→  };
398→
399→  const handleSubmitForValidation = (missionId: string) => {
400→    handleStatusChange(missionId, 'livraison');
401→  };
402→
403→  const formatDate = (iso: string) => new Date(iso).toLocaleDateString('fr-FR', { day: '2-digit', month: 'short', year: 'numeric' });
404→  const formatBudget = (amount: number, currency: string) => new Intl.NumberFormat('fr-FR', { style: 'currency', currency }).format(amount);
405→  const getScoreColor = (s: number) => s >= 70 ? 'text-green-400' : s >= 50 ? 'text-yellow-400' : s >= 30 ? 'text-orange-400' : 'text-red-400';
406→  const getScoreBg = (s: number) => s >= 70 ? 'bg-green-500/20' : s >= 50 ? 'bg-yellow-500/20' : s >= 30 ? 'bg-orange-500/20' : 'bg-red-500/20';
407→  const getDaysRemaining = (d: string) => Math.ceil((new Date(d).getTime() - Date.now()) / 86400000);
408→
409→  return (
410→    <div className="space-y-6 page-enter">
411→      <PageHeader title="Ordres de mission" description="Suivi et gestion de vos missions" />
412→      {/* Header */}
413→      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
414→        <div className="flex items-center gap-4">
415→          <button onClick={onBack} className="w-10 h-10 rounded-xl bg-white/5 border border-white/[0.06] flex items-center justify-center text-gray-400 hover:text-white hover:bg-white/10 transition-all">
416→            <ArrowLeft size={18} />
417→          </button>
418→          <div>
419→            <h1 className="text-2xl md:text-3xl font-bold text-white flex items-center gap-3">
420→              <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-orange-500 to-amber-600 flex items-center justify-center">
421→                <ClipboardList size={20} className="text-white" />
422→              </div>
423→              Ordres de Mission
424→            </h1>
425→            <p className="text-gray-500 text-sm mt-1">Demandes clients depuis CitedBy.ai Public</p>
